// 'items' é a lista de todos os itens que vêm do nó anterior (do Google Sheets).
const allItems = items;

// Usamos a função .map() para transformar cada item da lista em um novo objeto, com o formato que queremos.
const cleanedList = allItems.map(item => {
  // Para cada item, criamos um novo objeto com as chaves "Produto", "Foto" e "Descrição".
  return {
    // IMPORTANTE: Altere "PRODUTO" para o nome exato da coluna do produto na sua planilha.
    // Ex: item.json.NomeDoProduto, item.json.SKU, etc.
    "Produto": item.json.produto, 
    "Foto": item.json.foto_url,
    "Descrição": item.json.descricao
  };
});

// Por fim, retornamos a nova lista tratada. Esta será a saída do nó "Code".
return cleanedList;

